function togglePassword(fieldId){const field=document.getElementById(fieldId),icon=document.getElementById(fieldId+"-icon");"password"===field.type?(field.type="text",icon.classList.remove("fa-eye-slash"),icon.classList.add("fa-eye")):(field.type="password",icon.classList.remove("fa-eye"),icon.classList.add("fa-eye-slash"))}document.addEventListener("DOMContentLoaded",(function(){const form=document.querySelector('form[action*="action=register"]'),btn=document.querySelector(".btn-register");form&&btn&&form.addEventListener("submit",(function(){btn.disabled=!0,btn.innerHTML='<span class="spinner-border spinner-border-sm mr-2" role="status" aria-hidden="true"></span> Registering...'}))}));